---
import type { ImageMetadata } from "astro"
import { Image } from "astro:assets"

import { cn } from "@/lib/utils"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Icon } from "@/components/ui/icon"
import { Section, SectionContainer } from "@/components/ui/section"

type Props = {
  class?: string
  badge?: string
  title: string
  buttons?: {
    label: string
    href: string
    variant?: "default" | "outline" | "secondary" | "ghost"
  }[]
  services: {
    image: {
      src: ImageMetadata
      alt: string
    }
    label?: string
    title: string
    description: string
    href?: string
  }[]
}

const { class: className, badge, title, buttons, services } = Astro.props
---

<Section class={cn("", className)}>
  <SectionContainer class="gap-8">
    <div
      class="flex flex-col gap-4 md:flex-row md:items-end md:justify-between"
    >
      <div class="max-w-2xl">
        {badge && <Badge variant="secondary">{badge}</Badge>}
        <h2
          class="mt-4 text-3xl font-semibold tracking-tight text-balance sm:text-4xl"
        >
          {title}
        </h2>
      </div>
      {
        buttons?.length && (
          <div class="flex flex-wrap gap-3">
            {buttons.map(({ href, label, ...button }) => (
              <Button as="a" href={href} variant={button.variant}>
                {label}
              </Button>
            ))}
          </div>
        )
      }
    </div>
    <div class="grid gap-6 sm:grid-cols-2 lg:grid-cols-4">
      {
        services.map((service) => {
          const Wrapper = service.href ? "a" : "div"
          return (
            <Wrapper
              href={service.href}
              class={cn(
                "group/service flex flex-col gap-4 overflow-hidden rounded-xl border shadow-xs transition-shadow",
                service.href && "hover:shadow-md"
              )}
            >
              <Image
                src={service.image.src}
                alt={service.image.alt}
                class="aspect-4/3 w-full object-cover"
                widths={[320, 480, 640]}
                sizes="(min-width: 1024px) 25vw, (min-width: 640px) 50vw, 100vw"
              />
              <div class="flex flex-1 flex-col gap-2 px-5 pb-5">
                {service.label && (
                  <span class="text-primary text-xs font-medium">
                    {service.label}
                  </span>
                )}
                <h3 class="text-base font-medium">{service.title}</h3>
                <p class="text-muted-foreground text-sm leading-relaxed">
                  {service.description}
                </p>
                {service.href && (
                  <span class="mt-auto pt-2">
                    <Icon
                      name="arrow-right"
                      class="text-muted-foreground size-4 transition-transform group-hover/service:translate-x-1"
                    />
                  </span>
                )}
              </div>
            </Wrapper>
          )
        })
      }
    </div>
  </SectionContainer>
</Section>
